```class Solution {
public:
 int maxScore(string s) {
    int ones = 0;
    for (char c : s) {
        if (c == '1') ones++;
    }
    int max_score = 0;
    int zeros = 0;
    for (int i = 0; i < s.size() - 1; i++) {
        if (s[i] == '0') zeros++;
        else ones--;
        max_score = max(max_score, zeros + ones);
    }
    return max_score;
 }
};
